def analyze_function_complexity(node, language: str) -> ControlFlowMetrics:
    """
    Analyze control flow metrics for a single function node.

    Args:
        node: tree-sitter Node representing a function
        language: Language name

    Returns:
        ControlFlowMetrics for the function
    """
    # Create a fake "tree" with this node as root for reuse
    decision_nodes = DECISION_NODES.get(language, DECISION_NODES['python'])
    nesting_nodes = set(NESTING_NODES.get(language, NESTING_NODES['python']))

    decision_count = 0
    max_depth = 0
    loops = 0
    exception_handlers = 0
    early_returns = 0
    branches = 0

    loop_types = {'for_statement', 'for_in_statement', 'while_statement', 'do_statement'}
    exception_types = {'except_clause', 'catch_clause'}

    def visit(n, depth):
        nonlocal decision_count, max_depth, loops, exception_handlers, early_returns, branches

        node_type = n.type

        # Nesting
        new_depth = depth
        if node_type in nesting_nodes:
            new_depth = depth + 1
            if new_depth > max_depth:
                max_depth = new_depth

        # Decision points
        if node_type in decision_nodes:
            decision_count += decision_nodes[node_type]

        # Boolean operators
        if language == 'python' and node_type == 'boolean_operator':
            for child in n.children:
                if child.type in ('and', 'or'):
                    decision_count += 1
                    break

        if language in ('javascript', 'typescript') and node_type == 'binary_expression':
            for child in n.children:
                if child.type in ('&&', '||'):
                    decision_count += 1
                    break

        # Specific counts
        if node_type in loop_types:
            loops += 1

        if node_type in exception_types:
            exception_handlers += 1

        if node_type in ('if_statement', 'elif_clause', 'switch_case'):
            branches += 1

        if node_type == 'return_statement':
            early_returns += 1

        for child in n.children:
            visit(child, new_depth)

    visit(node, 0)

    # Adjust early returns
    if early_returns > 0:
        early_returns = max(0, early_returns - 1)

    return ControlFlowMetrics(
        cyclomatic_complexity=decision_count + 1,
        max_nesting_depth=max_depth,
        decision_points=decision_count,
        branches=branches,
        early_returns=early_returns,
        loops=loops,
        exception_handlers=exception_handlers,
    )

def complex_function(x, y):
    if x > 0:
        for i in range(x):
            if i % 2 == 0:
                try:
                    result = y / i
                except ZeroDivisionError:
                    return None
                if result > 10:
                    return result
    elif x < 0:
        while y > 0:
            y -= 1
    else:
        return x and y or 0
    return y

def _get_language(lang: str):
    """Lazy load language module."""
    global _languages
    if lang not in _languages:
        if lang == 'python':
            import tree_sitter_python
            _languages[lang] = tree_sitter_python.language()
        elif lang in ('javascript', 'typescript'):
            import tree_sitter_javascript
            _languages[lang] = tree_sitter_javascript.language()
        else:
            return None
    return _languages[lang]

SIDE_EFFECT_FUNCTIONS = {
    'python': {
        'io': ['print', 'input', 'open', 'read', 'write', 'close', 'flush'],
        'external': ['requests', 'urllib', 'socket', 'subprocess', 'os.system'],
        'global': ['globals', 'setattr', 'delattr', 'exec', 'eval'],
    },
    'javascript': {
        'io': ['console.log', 'console.error', 'alert', 'prompt', 'fetch'],
        'external': ['XMLHttpRequest', 'WebSocket', 'localStorage', 'sessionStorage'],
        'global': ['eval', 'document.write'],
    },

MUTATING_METHODS = {
    'python': {
        # List mutations
        'append', 'extend', 'insert', 'pop', 'remove', 'clear', 'reverse', 'sort',
        # Dict mutations
        'update', 'pop', 'popitem', 'clear', 'setdefault',
        # Set mutations
        'add', 'discard', 'remove', 'pop', 'clear',
        'update', 'intersection_update', 'difference_update', 'symmetric_difference_update',
    },
    'javascript': {
        # Array mutations
        'push', 'pop', 'shift', 'unshift', 'splice', 'reverse', 'sort', 'fill', 'copyWithin',
        # Map/Set mutations
        'set', 'delete', 'clear',
    },

def _analyze_python_data_flow(tree, source: bytes, graph: DataFlowGraph):
    """Analyze Python data flow using AST traversal."""
    # Track variables declared global/nonlocal for is_global_write detection
    global_vars: set = set()

    def visit_node(node):
        node_type = node.type

        # Regular assignment: x = value
        if node_type == 'assignment':
            _process_python_assignment(node, source, graph, global_vars)

        # Augmented assignment: x += value (mutation)
        elif node_type == 'augmented_assignment':
            _process_python_augmented_assignment(node, source, graph, global_vars)

        # Attribute assignment: obj.attr = value (mutation)
        elif node_type == 'assignment' and _is_attribute_target(node):
            # Already handled in _process_python_assignment
            pass

        # Global/nonlocal declarations
        elif node_type in ('global_statement', 'nonlocal_statement'):
            _process_global_statement(node, source, graph, global_vars)

        # Function calls that may have side effects or mutate objects
        elif node_type == 'call':
            _check_side_effect_call(node, source, graph, 'python')
            _check_mutating_method_call(node, source, graph, 'python')

        # Delete statement (mutation)
        elif node_type == 'delete_statement':
            _process_delete_statement(node, source, graph)

        # Recurse
        for child in node.children:
            visit_node(child)

    visit_node(tree.root_node)

def _analyze_js_data_flow(tree, source: bytes, graph: DataFlowGraph):
    """Analyze JavaScript/TypeScript data flow."""

    def visit_node(node):
        node_type = node.type

        # Variable declaration with initializer
        if node_type == 'variable_declarator':
            _process_js_declarator(node, source, graph)

        # Assignment expression
        elif node_type == 'assignment_expression':
            _process_js_assignment(node, source, graph)

        # Augmented assignment
        elif node_type == 'augmented_assignment_expression':
            _process_js_augmented_assignment(node, source, graph)

        # Update expression (++, --)
        elif node_type == 'update_expression':
            _process_js_update(node, source, graph)

        # Function calls
        elif node_type == 'call_expression':
            _check_side_effect_call(node, source, graph, 'javascript')
            _check_mutating_method_call(node, source, graph, 'javascript')

        # Recurse
        for child in node.children:
            visit_node(child)

    visit_node(tree.root_node)

def _get_python_target_name(node, source: bytes) -> Tuple[str, bool]:
    """Get target name and whether it's an attribute write."""
    if node.type == 'identifier':
        name = source[node.start_byte:node.end_byte].decode('utf8', errors='replace')
        return name, False
    elif node.type == 'attribute':
        # Get full attribute path: obj.attr
        text = source[node.start_byte:node.end_byte].decode('utf8', errors='replace')
        return text, True
    elif node.type == 'subscript':
        # Array/dict indexing: arr[i]
        text = source[node.start_byte:node.end_byte].decode('utf8', errors='replace')
        return text, True
    elif node.type == 'tuple_pattern' or node.type == 'list_pattern':
        # Destructuring: a, b = ...
        return '<destructured>', False
    else:
        text = source[node.start_byte:node.end_byte].decode('utf8', errors='replace')
        return text, False

def _is_attribute_target(node) -> bool:
    """Check if assignment target is an attribute access."""
    left = node.child_by_field_name('left')
    if left and left.type in ('attribute', 'subscript', 'member_expression', 'subscript_expression'):
        return True
    return False

def _extract_referenced_names(node, source: bytes) -> List[str]:
    """Extract all identifier names referenced in a node."""
    if node is None:
        return []

    names = []

    def collect_names(n):
        if n.type == 'identifier':
            name = source[n.start_byte:n.end_byte].decode('utf8', errors='replace')
            names.append(name)
        for child in n.children:
            collect_names(child)

    collect_names(node)
    return names

def _check_side_effect_call(node, source: bytes, graph: DataFlowGraph, language: str):
    """Check if a function call has side effects."""
    indicators = SIDE_EFFECT_FUNCTIONS.get(language, {})

    # Get the function name being called
    func_node = node.child_by_field_name('function')
    if not func_node:
        for child in node.children:
            if child.type in ('identifier', 'attribute', 'member_expression'):
                func_node = child
                break

    if not func_node:
        return

    func_name = source[func_node.start_byte:func_node.end_byte].decode('utf8', errors='replace')

    # Check against known side effect indicators
    for effect_kind, names in indicators.items():
        for indicator in names:
            if indicator in func_name or func_name == indicator:
                effect = SideEffect(
                    kind=effect_kind,
                    name=func_name,
                    line=node.start_point[0] + 1,
                    evidence=f"Call to {func_name}",
                )
                graph.side_effects.append(effect)
                return

def _check_mutating_method_call(node, source: bytes, graph: DataFlowGraph, language: str):
    """
    Check if a method call mutates its receiver object.

    Detects patterns like: list.append(), dict.update(), set.add()
    These are recorded as mutations even though they don't use assignment syntax.
    """
    mutating_methods = MUTATING_METHODS.get(language, set())
    if not mutating_methods:
        return

    # Get the function/method being called
    func_node = node.child_by_field_name('function')
    if not func_node:
        for child in node.children:
            if child.type in ('attribute', 'member_expression'):
                func_node = child
                break

    if not func_node:
        return

    # Check if it's a method call (attribute access)
    if func_node.type not in ('attribute', 'member_expression'):
        return

    # Get the method name (the last part of the attribute chain)
    method_name = None
    if func_node.type == 'attribute':
        # Python: obj.method
        attr_node = func_node.child_by_field_name('attribute')
        if attr_node:
            method_name = source[attr_node.start_byte:attr_node.end_byte].decode('utf8', errors='replace')
    elif func_node.type == 'member_expression':
        # JavaScript: obj.method
        prop_node = func_node.child_by_field_name('property')
        if prop_node:
            method_name = source[prop_node.start_byte:prop_node.end_byte].decode('utf8', errors='replace')

    if not method_name:
        # Fallback: try to extract from children
        for child in func_node.children:
            if child.type == 'identifier' and child != func_node.children[0]:
                method_name = source[child.start_byte:child.end_byte].decode('utf8', errors='replace')
                break

    if method_name and method_name in mutating_methods:
        # Get the receiver object name
        receiver_name = '<object>'
        if func_node.type == 'attribute':
            obj_node = func_node.child_by_field_name('object')
            if obj_node:
                receiver_name = source[obj_node.start_byte:obj_node.end_byte].decode('utf8', errors='replace')
        elif func_node.type == 'member_expression':
            obj_node = func_node.child_by_field_name('object')
            if obj_node:
                receiver_name = source[obj_node.start_byte:obj_node.end_byte].decode('utf8', errors='replace')

        # Record as a mutation
        assignment = Assignment(
            target_name=receiver_name,
            target_node_id=func_node.id,
            source_names=[],
            start_line=node.start_point[0] + 1,
            start_byte=node.start_byte,
            end_byte=node.end_byte,
            is_mutation=True,
            is_attribute_write=True,  # Method mutation is similar to attribute write
        )

        graph.assignments.append(assignment)
        graph.mutations.append(assignment)

def _count_mutation_types(graph: DataFlowGraph) -> Dict[str, int]:
    """Count mutations by type."""
    counts = {'attribute_write': 0, 'augmented': 0, 'other': 0}
    for m in graph.mutations:
        if m.is_attribute_write:
            counts['attribute_write'] += 1
        elif len(m.source_names) > 0 and m.target_name in m.source_names:
            counts['augmented'] += 1
        else:
            counts['other'] += 1
    return counts

def _count_side_effect_types(graph: DataFlowGraph) -> Dict[str, int]:
    """Count side effects by type."""
    counts = {}
    for effect in graph.side_effects:
        counts[effect.kind] = counts.get(effect.kind, 0) + 1
    return counts

def analyze_function_purity(func_node, source: bytes, language: str) -> Tuple[float, Dict]:
    """
    Analyze purity of a single function.

    Args:
        func_node: tree-sitter node for the function
        source: Full source code as bytes
        language: Language name

    Returns:
        Tuple of (purity_score, factors_dict)
    """
    # Create a mini data flow graph for just this function
    graph = DataFlowGraph(file_path='', language=language)

    if language == 'python':
        def visit(node):
            if node.type == 'assignment':
                _process_python_assignment(node, source, graph)
            elif node.type == 'augmented_assignment':
                _process_python_augmented_assignment(node, source, graph)
            elif node.type == 'call':
                _check_side_effect_call(node, source, graph, 'python')
            for child in node.children:
                visit(child)
        visit(func_node)

    elif language in ('javascript', 'typescript'):
        def visit(node):
            if node.type == 'assignment_expression':
                _process_js_assignment(node, source, graph)
            elif node.type == 'augmented_assignment_expression':
                _process_js_augmented_assignment(node, source, graph)
            elif node.type == 'update_expression':
                _process_js_update(node, source, graph)
            elif node.type == 'call_expression':
                _check_side_effect_call(node, source, graph, 'javascript')
            for child in node.children:
                visit(child)
        visit(func_node)

    graph.pure_score = calculate_purity(graph)
    return graph.pure_score, get_purity_factors(graph)

class Counter:
    def increment(self):
        self.count += 1     # mutation (attribute write)

def validate_node(node: Dict[str, Any]) -> Tuple[List[str], List[str]]:
    """Validate a node dict. Returns (errors, warnings)."""
    errors: List[str] = []
    warnings: List[str] = []

    # Required fields
    if not node.get('id'):
        errors.append("Node missing required 'id' field")
    else:
        node_id = str(node["id"])
        if ID_CANONICAL_PATTERN.match(node_id):
            pass
        elif ID_LEGACY_PATTERN.match(node_id):
            warnings.append(f"Legacy id format: {node_id}")
        else:
            warnings.append(f"Non-canonical id format: {node_id}")

    if not node.get('name'):
        errors.append("Node missing required 'name' field")

    # Confidence range (canonical: 0.0-1.0)
    for key, value in node.items():
        if not is_confidence_key(key):
            continue
        try:
            numeric = float(value)
        except (TypeError, ValueError):
            errors.append(f"{key} not numeric: {value}")
            continue
        if not 0.0 <= numeric <= 1.0:
            errors.append(f"{key} out of range (0.0-1.0): {value}")

    atom = node.get('atom')
    if atom and isinstance(atom, str) and not ATOM_PATTERN.match(atom):
        warnings.append(f"Atom format mismatch: {atom}")

    return errors, warnings

def validate_edge(edge: Dict[str, Any], node_ids: Set[str]) -> Tuple[List[str], List[str]]:
    """Validate an edge dict. Returns (errors, warnings)."""
    errors: List[str] = []
    warnings: List[str] = []

    if not edge.get('source'):
        errors.append("Edge missing 'source'")
    elif edge['source'] not in node_ids:
        errors.append(f"Edge source not in graph: {edge['source'][:50]}...")

    if not edge.get('target'):
        errors.append("Edge missing 'target'")
    # Target may be external - don't error

    for key, value in edge.items():
        if not is_confidence_key(key):
            continue
        try:
            numeric = float(value)
        except (TypeError, ValueError):
            errors.append(f"Edge {key} not numeric: {value}")
            continue
        if not 0.0 <= numeric <= 1.0:
            errors.append(f"Edge {key} out of range 0.0-1.0: {value}")

    return errors, warnings

class SourceLocation:
    """Pinpoints a deviation in the codebase."""
    file_path: str
    line_number: int = 0
    column: int = 0
    context: str = ""  # Surrounding code/doc snippet

    def __str__(self) -> str:
        if self.line_number:
            return f"{self.file_path}:{self.line_number}"
        return self.file_path

def diagnose_mistake(state: str, blame: Optional["GitBlame"], symbol: str,
                     evidence: Optional[MistakeEvidence] = None) -> str:
    """
    Analyze the deviation and explain what went wrong.

    Returns a human-readable explanation of the mistake.
    """
    if evidence:
        # We have hard evidence from git analysis
        return f"{evidence.diagnosis} [{evidence.confidence} confidence, {evidence.evidence_type}]"

    if not blame:
        return f"Unknown origin - no git history available for {symbol}"

    # Fallback to commit message heuristics (LOW confidence)
    msg = blame.commit_message.lower()

    if state == "UNVOICED":
        # Code exists without documentation
        if any(kw in msg for kw in ["feat", "add", "implement", "create", "new"]):
            return f"[INFERRED] Feature added without docs. Commit '{blame.commit_message[:40]}' suggests new code."
        elif any(kw in msg for kw in ["refactor", "move", "rename", "reorganize"]):
            return f"[INFERRED] Refactoring may have broken doc links. Commit suggests restructuring."
        elif any(kw in msg for kw in ["fix", "bug", "patch", "hotfix"]):
            return f"[INFERRED] Bug fix may have added undocumented code."
        else:
            return f"[INFERRED] Code exists without docs. Cause unclear from commit message alone."

    elif state == "UNREALIZED":
        # Documentation exists without code
        if any(kw in msg for kw in ["doc", "readme", "spec", "plan"]):
            return f"[INFERRED] Docs written before implementation. Spec may never have been built."
        elif any(kw in msg for kw in ["delete", "remove", "deprecate", "drop"]):
            return f"[INFERRED] Code may have been removed without updating docs."
        else:
            return f"[INFERRED] Docs reference missing code. Either never built or removed."

    elif state == "DISCORDANT":
        return f"[INFERRED] Code and docs exist but may describe different purposes."

    return f"[INFERRED] Deviation detected but cause unclear from available evidence."

class DeviationReport:
    """Complete deviation analysis with source tracing."""
    timestamp: str
    total_deviations: int
    by_state: Dict[str, int]
    by_author: Dict[str, int]
    deviations: List[Deviation]
    oldest_deviation: Optional[Deviation] = None
    newest_deviation: Optional[Deviation] = None

    def to_dict(self) -> dict:
        return {
            "timestamp": self.timestamp,
            "summary": {
                "total": self.total_deviations,
                "by_state": self.by_state,
                "by_author": self.by_author
            },
            "oldest": self.oldest_deviation.to_dict() if self.oldest_deviation else None,
            "newest": self.newest_deviation.to_dict() if self.newest_deviation else None,
            "deviations": [d.to_dict() for d in self.deviations]
        }

    def to_json(self, indent: int = 2) -> str:
        return json.dumps(self.to_dict(), indent=indent, default=str)

class DeviationTracker:
    """Traces concordance deviations to their git source."""

    def __init__(self, repo_path: Path):
        self.repo_path = Path(repo_path)
        self._git_available = self._check_git()

    def _check_git(self) -> bool:
        """Check if git is available and repo is valid."""
        try:
            result = subprocess.run(
                ["git", "rev-parse", "--git-dir"],
                cwd=self.repo_path,
                capture_output=True,
                text=True
            )
            return result.returncode == 0
        except Exception:
            return False

    def _git_blame_line(self, file_path: str, line_number: int) -> Optional[GitBlame]:
        """Get git blame for a specific line."""
        if not self._git_available or line_number <= 0:
            return None

        try:
            # Use porcelain format for parsing
            result = subprocess.run(
                ["git", "blame", "-L", f"{line_number},{line_number}",
                 "--porcelain", file_path],
                cwd=self.repo_path,
                capture_output=True,
                text=True,
                timeout=10
            )

            if result.returncode != 0:
                return None

            lines = result.stdout.strip().split('\n')
            if not lines:
                return None

            # Parse porcelain output
            commit_sha = lines[0].split()[0]
            author = ""
            author_email = ""
            timestamp = datetime.now()

            for line in lines[1:]:
                if line.startswith("author "):
                    author = line[7:]
                elif line.startswith("author-mail "):
                    author_email = line[12:].strip("<>")
                elif line.startswith("author-time "):
                    ts = int(line[12:])
                    timestamp = datetime.fromtimestamp(ts)

            # Get commit message
            msg_result = subprocess.run(
                ["git", "log", "-1", "--format=%s", commit_sha],
                cwd=self.repo_path,
                capture_output=True,
                text=True,
                timeout=5
            )
            commit_message = msg_result.stdout.strip() if msg_result.returncode == 0 else ""

            return GitBlame(
                commit_sha=commit_sha,
                author=author,
                author_email=author_email,
                timestamp=timestamp,
                commit_message=commit_message
            )

        except Exception:
            return None

    def _analyze_commit_evidence(self, commit_sha: str, file_path: str,
                                   symbol: str, state: str) -> Optional[MistakeEvidence]:
        """
        Analyze git diff to get HARD EVIDENCE of what happened.

        This looks at the actual commit to determine:
        1. Did this commit ADD the code/docs?
        2. Did this commit touch BOTH code and docs?
        3. What files were changed?
        """
        if not self._git_available:
            return None

        try:
            # Get list of files changed in this commit
            result = subprocess.run(
                ["git", "show", "--name-status", "--format=", commit_sha],
                cwd=self.repo_path,
                capture_output=True,
                text=True,
                timeout=10
            )

            if result.returncode != 0:
                return None

            changed_files = result.stdout.strip().split('\n')

            code_files_changed = []
            doc_files_changed = []

            for line in changed_files:
                if not line.strip():
                    continue
                parts = line.split('\t')
                if len(parts) < 2:
                    continue
                status, filepath = parts[0], parts[1]

                if filepath.endswith(('.py', '.js', '.ts', '.go', '.rs')):
                    code_files_changed.append((status, filepath))
                elif filepath.endswith(('.md', '.rst', '.txt')) or 'doc' in filepath.lower():
                    doc_files_changed.append((status, filepath))

            # Analyze the evidence
            commit_added_code = any(s in ('A', 'M') for s, _ in code_files_changed)
            commit_touched_docs = len(doc_files_changed) > 0

            # Determine diagnosis based on EVIDENCE
            if state == "UNVOICED":
                if commit_added_code and not commit_touched_docs:
                    return MistakeEvidence(
                        diagnosis=f"Code added in {commit_sha[:8]} without documentation update",
                        confidence="HIGH",
                        evidence_type="DIFF",
                        details=f"Commit modified {len(code_files_changed)} code files, 0 doc files",
                        commit_added_code=True,
                        commit_touched_docs=False
                    )
                elif commit_added_code and commit_touched_docs:
                    return MistakeEvidence(
                        diagnosis=f"Code and docs both changed, but symbol not documented",
                        confidence="MEDIUM",
                        evidence_type="DIFF",
                        details=f"Commit touched docs but missed this symbol",
                        commit_added_code=True,
                        commit_touched_docs=True
                    )

            elif state == "UNREALIZED":
                if commit_touched_docs and not commit_added_code:
                    return MistakeEvidence(
                        diagnosis=f"Documentation added in {commit_sha[:8]} without corresponding code",
                        confidence="HIGH",
                        evidence_type="DIFF",
                        details=f"Commit modified {len(doc_files_changed)} doc files, 0 code files",
                        commit_added_code=False,
                        commit_touched_docs=True
                    )

            return None

        except Exception:
            return None

    def _git_log_file(self, file_path: str) -> Optional[GitBlame]:
        """Get the last modification info for a file."""
        if not self._git_available:
            return None

        try:
            result = subprocess.run(
                ["git", "log", "-1", "--format=%H|%an|%ae|%at|%s", "--", file_path],
                cwd=self.repo_path,
                capture_output=True,
                text=True,
                timeout=10
            )

            if result.returncode != 0 or not result.stdout.strip():
                return None

            parts = result.stdout.strip().split("|", 4)
            if len(parts) < 5:
                return None

            return GitBlame(
                commit_sha=parts[0],
                author=parts[1],
                author_email=parts[2],
                timestamp=datetime.fromtimestamp(int(parts[3])),
                commit_message=parts[4]
            )

        except Exception:
            return None

    def _find_symbol_location(self, symbol: str, search_code: bool = True) -> Optional[SourceLocation]:
        """Find where a symbol is defined/referenced."""
        # Extract the simple name from qualified path
        parts = symbol.split(".")
        simple_name = parts[-1]

        # Determine search path based on symbol structure
        if search_code:
            # Search in Python files
            search_patterns = ["*.py"]
            search_dir = self.repo_path / "src"
            if not search_dir.exists():
                search_dir = self.repo_path
        else:
            # Search in documentation
            search_patterns = ["*.md"]
            search_dir = self.repo_path / "docs"
            if not search_dir.exists():
                search_dir = self.repo_path

        for pattern in search_patterns:
            for file_path in search_dir.rglob(pattern):
                try:
                    content = file_path.read_text(encoding='utf-8')
                    lines = content.split('\n')

                    for i, line in enumerate(lines, 1):
                        # Look for definition patterns
                        if search_code:
                            # Python: def func, class Cls, CONST =
                            if re.search(rf'\b(def|class)\s+{re.escape(simple_name)}\b', line):
                                return SourceLocation(
                                    file_path=str(file_path.relative_to(self.repo_path)),
                                    line_number=i,
                                    context=line.strip()[:100]
                                )
                            if re.match(rf'^{re.escape(simple_name)}\s*=', line):
                                return SourceLocation(
                                    file_path=str(file_path.relative_to(self.repo_path)),
                                    line_number=i,
                                    context=line.strip()[:100]
                                )
                        else:
                            # Markdown: mentions in code blocks or headers
                            if simple_name in line:
                                return SourceLocation(
                                    file_path=str(file_path.relative_to(self.repo_path)),
                                    line_number=i,
                                    context=line.strip()[:100]
                                )
                except Exception:
                    continue

        return None

    def trace_unvoiced(self, symbol: str) -> Deviation:
        """Trace an UNVOICED deviation (code without docs)."""
        location = self._find_symbol_location(symbol, search_code=True)

        if not location:
            location = SourceLocation(file_path="unknown", context=f"Symbol: {symbol}")

        blame = None
        evidence = None

        if location.line_number > 0:
            blame = self._git_blame_line(location.file_path, location.line_number)
        elif location.file_path != "unknown":
            blame = self._git_log_file(location.file_path)

        # Get HARD EVIDENCE from git diff
        if blame:
            evidence = self._analyze_commit_evidence(
                blame.commit_sha, location.file_path, symbol, "UNVOICED"
            )

        diagnosis = diagnose_mistake("UNVOICED", blame, symbol, evidence)

        return Deviation(
            symbol=symbol,
            state="UNVOICED",
            location=location,
            blame=blame,
            suggested_action=f"Add documentation for {symbol} in docs/",
            diagnosis=diagnosis
        )

    def trace_unrealized(self, symbol: str) -> Deviation:
        """Trace an UNREALIZED deviation (docs without code)."""
        location = self._find_symbol_location(symbol, search_code=False)

        if not location:
            location = SourceLocation(file_path="unknown", context=f"Reference: {symbol}")

        blame = None
        evidence = None

        if location.line_number > 0:
            blame = self._git_blame_line(location.file_path, location.line_number)
        elif location.file_path != "unknown":
            blame = self._git_log_file(location.file_path)

        # Get HARD EVIDENCE from git diff
        if blame:
            evidence = self._analyze_commit_evidence(
                blame.commit_sha, location.file_path, symbol, "UNREALIZED"
            )

        diagnosis = diagnose_mistake("UNREALIZED", blame, symbol, evidence)

        return Deviation(
            symbol=symbol,
            state="UNREALIZED",
            location=location,
            blame=blame,
            suggested_action=f"Implement {symbol} or remove from documentation",
            diagnosis=diagnosis
        )

    def trace_from_symmetry_report(self, report_dict: dict) -> DeviationReport:
        """
        Trace all deviations from a SymmetryReport.

        Args:
            report_dict: Output from SymmetryReport.to_dict()
        """
        deviations = []

        # Trace undocumented (UNVOICED)
        undocumented = report_dict.get("top_offenders", {}).get("undocumented", [])
        for symbol in undocumented:
            dev = self.trace_unvoiced(symbol)
            deviations.append(dev)

        # Trace orphan docs (UNREALIZED)
        orphan_docs = report_dict.get("top_offenders", {}).get("orphan_docs", [])
        for symbol in orphan_docs:
            dev = self.trace_unrealized(symbol)
            deviations.append(dev)

        # Count by state
        by_state = {}
        for dev in deviations:
            by_state[dev.state] = by_state.get(dev.state, 0) + 1

        # Count by author
        by_author = {}
        for dev in deviations:
            if dev.blame:
                author = dev.blame.author
                by_author[author] = by_author.get(author, 0) + 1

        # Find oldest and newest
        dated = [d for d in deviations if d.blame]
        oldest = min(dated, key=lambda d: d.blame.timestamp) if dated else None
        newest = max(dated, key=lambda d: d.blame.timestamp) if dated else None

        return DeviationReport(
            timestamp=datetime.now().isoformat(),
            total_deviations=len(deviations),
            by_state=by_state,
            by_author=by_author,
            deviations=deviations,
            oldest_deviation=oldest,
            newest_deviation=newest
        )

    def trace_directory(self, code_dir: Path, docs_dir: Path) -> DeviationReport:
        """
        Quick trace without full symmetry analysis.
        Compares code definitions with doc mentions.
        """
        from .visibility_analyzer import VisibilityAnalyzer
        from .wave_extractor import WaveExtractor
        from .identity_matcher import IdentityMatcher

        # Extract code symbols
        code_symbols = []
        for py_file in code_dir.rglob("*.py"):
            if "test" in str(py_file) or ".venv" in str(py_file):
                continue
            try:
                source = py_file.read_text(encoding='utf-8')
                module = str(py_file.relative_to(code_dir)).replace("/", ".").replace(".py", "")
                analyzer = VisibilityAnalyzer(source, module)
                for name in analyzer.get_public_exports():
                    code_symbols.append(f"{module}.{name}" if "." not in name else name)
            except Exception:
                continue

        # Extract doc references
        extractor = WaveExtractor(docs_dir)
        doc_nodes = extractor.extract_all()
        doc_symbols = list(set(node.id for node in doc_nodes))

        # Match
        matcher = IdentityMatcher(threshold=0.75)
        result = matcher.match(doc_symbols, code_symbols)

        # Build report dict matching SymmetryReport structure
        report_dict = {
            "top_offenders": {
                "undocumented": result.undocumented[:20],
                "orphan_docs": result.orphan_docs[:20]
            }
        }

        return self.trace_from_symmetry_report(report_dict)

class TreeSitterDimensionClassifier:
    """
    Tree-sitter based dimension classifier.
    Uses .scm query files for accurate AST-based pattern detection.
    """

    def __init__(self):
        self._parser = None
        self._language = None
        self._queries: Dict[str, Any] = {}
        self._query_text: Dict[str, str] = {}
        self._initialized = False

    def _ensure_initialized(self, language: str = 'python') -> bool:
        """Lazy initialization of tree-sitter parser and queries."""
        if self._initialized and self._current_language == language:
            return True

        try:
            import tree_sitter

            # Get language module
            if language == 'python':
                import tree_sitter_python
                lang_obj = tree_sitter_python.language()
            elif language == 'javascript':
                import tree_sitter_javascript
                lang_obj = tree_sitter_javascript.language()
            elif language == 'typescript':
                import tree_sitter_typescript
                lang_obj = tree_sitter_typescript.language_typescript()
            else:
                logger.debug(f"No tree-sitter support for {language}")
                return False

            # Create parser
            self._parser = tree_sitter.Parser()
            self._language = tree_sitter.Language(lang_obj)
            self._parser.language = self._language
            self._current_language = language

            # Load queries
            self._load_queries(language)

            self._initialized = True
            return True

        except ImportError as e:
            logger.debug(f"Tree-sitter not available: {e}")
            return False
        except Exception as e:
            logger.warning(f"Failed to initialize tree-sitter: {e}")
            return False

    def _load_queries(self, language: str):
        """Load .scm query files for dimension classification."""
        import tree_sitter

        try:
            from src.core.queries import get_query_loader
        except ImportError:
            try:
                from core.queries import get_query_loader
            except ImportError:
                from queries import get_query_loader

        loader = get_query_loader()

        for query_type in ['boundary', 'state', 'lifecycle', 'roles', 'layer']:
            query_text = loader.load_query(language, query_type)
            if query_text:
                try:
                    self._queries[query_type] = tree_sitter.Query(self._language, query_text)
                    self._query_text[query_type] = query_text
                    logger.debug(f"Loaded {query_type}.scm for {language}")
                except Exception as e:
                    logger.warning(f"Failed to compile {query_type} query: {e}")

    def classify_boundary(self, source: str, language: str = 'python') -> BoundaryType:
        """Classify boundary type using tree-sitter queries."""
        if not self._ensure_initialized(language):
            return None

        if 'boundary' not in self._queries:
            return None

        tree = self._parser.parse(bytes(source, 'utf8'))
        captures = self._run_query('boundary', tree.root_node)

        has_input = any('input' in tag for tag in captures)
        has_output = any('output' in tag for tag in captures)

        if has_input and has_output:
            return BoundaryType.IO
        elif has_input:
            return BoundaryType.INPUT
        elif has_output:
            return BoundaryType.OUTPUT
        else:
            return BoundaryType.INTERNAL

    def classify_state(self, source: str, language: str = 'python') -> StateType:
        """Classify state type using tree-sitter queries."""
        if not self._ensure_initialized(language):
            return None

        if 'state' not in self._queries:
            return None

        tree = self._parser.parse(bytes(source, 'utf8'))
        captures = self._run_query('state', tree.root_node)

        # Any state-related capture indicates stateful
        if captures:
            return StateType.STATEFUL
        return StateType.STATELESS

    def classify_lifecycle(self, source: str, name: str, language: str = 'python') -> LifecyclePhase:
        """Classify lifecycle phase using tree-sitter queries."""
        if not self._ensure_initialized(language):
            return None

        if 'lifecycle' not in self._queries:
            return None

        tree = self._parser.parse(bytes(source, 'utf8'))
        captures = self._run_query('lifecycle', tree.root_node)

        # Check capture tags for lifecycle phase
        has_create = any('create' in tag for tag in captures)
        has_destroy = any('destroy' in tag for tag in captures)

        if has_create:
            return LifecyclePhase.CREATE
        elif has_destroy:
            return LifecyclePhase.DESTROY
        else:
            return LifecyclePhase.USE

    def classify_layer(self, source: str, language: str = 'python') -> Optional[LayerType]:
        """Classify Clean Architecture layer using tree-sitter queries."""
        if not self._ensure_initialized(language):
            return None

        if 'layer' not in self._queries:
            return None

        tree = self._parser.parse(bytes(source, 'utf8'))
        captures = self._run_query('layer', tree.root_node)

        # Check capture tags for layer classification
        # Priority: Test > Interface > Infrastructure > Application > Core
        # (Test is special case, Interface/Infrastructure are boundaries)
        layer_priority = [
            ('test', LayerType.TEST),
            ('interface', LayerType.INTERFACE),
            ('infrastructure', LayerType.INFRASTRUCTURE),
            ('application', LayerType.APPLICATION),
            ('core', LayerType.CORE),
        ]

        for layer_key, layer_type in layer_priority:
            if any(f'layer.{layer_key}' in tag for tag in captures):
                return layer_type

        return None  # Let fallback handle unknown

    def classify_role(self, source: str, name: str = '', language: str = 'python') -> Optional[Dict[str, Any]]:
        """
        Classify D3_ROLE using tree-sitter roles.scm queries.

        Returns dict with:
            - role: canonical role name (Repository, Service, Controller, etc.)
            - confidence: detection confidence (0-100)
            - evidence: list of matching patterns

        Returns None if tree-sitter unavailable or no role detected.
        """
        if not self._ensure_initialized(language):
            return None

        if 'roles' not in self._queries:
            return None

        tree = self._parser.parse(bytes(source, 'utf8'))
        captures = self._run_query_with_details('roles', tree.root_node, source)

        if not captures:
            return None

        # Prioritize roles by specificity (more specific patterns win)
        role_priority = [
            'repository', 'service', 'controller', 'factory',
            'validator', 'handler', 'mapper', 'guard', 'emitter',
            'asserter', 'lifecycle', 'parser', 'processor', 'adapter',
            'builder', 'enricher', 'extractor', 'scanner', 'predicate',
            'reporter', 'query', 'accessor', 'internal', 'utility'
        ]

        detected_roles = {}
        for tag, details in captures.items():
            # Extract role from tag like 'role.repository.class'
            if tag.startswith('role.'):
                parts = tag.split('.')
                if len(parts) >= 2:
                    role_type = parts[1]
                    if role_type not in detected_roles:
                        detected_roles[role_type] = {
                            'patterns': [],
                            'confidence': ROLE_CONFIDENCE.get(role_type, 50)
                        }
                    detected_roles[role_type]['patterns'].extend(details)

        if not detected_roles:
            return None

        # Select best role by priority
        best_role = None
        for role in role_priority:
            if role in detected_roles:
                best_role = role
                break

        if not best_role:
            best_role = list(detected_roles.keys())[0]

        # Map to canonical role names
        canonical_map = {
            'repository': 'Repository',
            'service': 'Service',
            'controller': 'Controller',
            'factory': 'Factory',
            'handler': 'Handler',
            'validator': 'Validator',
            'mapper': 'Mapper',
            'utility': 'Utility',
            'asserter': 'Asserter',
            'guard': 'Guard',
            'emitter': 'Emitter',
            'lifecycle': 'Lifecycle',
            'internal': 'Internal',
            # Extended roles
            'query': 'Query',
            'processor': 'Processor',
            'parser': 'Parser',
            'accessor': 'Accessor',
            'adapter': 'Adapter',
            'builder': 'Builder',
            'predicate': 'Predicate',
            'reporter': 'Reporter',
            'scanner': 'Scanner',
            'extractor': 'Extractor',
            'enricher': 'Enricher',
        }

        return {
            'role': canonical_map.get(best_role, best_role.title()),
            'confidence': detected_roles[best_role]['confidence'],
            'evidence': detected_roles[best_role]['patterns'][:3],  # Top 3 patterns
            'all_detected': list(detected_roles.keys()),
        }

    def _run_query_with_details(self, query_type: str, root_node, source: str) -> Dict[str, List[str]]:
        """Run a query and return captures with matched text."""
        import tree_sitter

        query = self._queries.get(query_type)
        if not query:
            return {}

        cursor = tree_sitter.QueryCursor(query)
        captures = cursor.captures(root_node)

        result = {}
        for tag, nodes in captures.items():
            if tag.startswith('_'):  # Skip internal captures
                continue
            if nodes:
                matched_texts = []
                for node in nodes[:5]:  # Limit to 5 matches per tag
                    text = source[node.start_byte:node.end_byte]
                    if len(text) > 50:
                        text = text[:50] + '...'
                    matched_texts.append(text)
                result[tag] = matched_texts
        return result

    def _run_query(self, query_type: str, root_node) -> Set[str]:
        """Run a query and return set of capture tag names."""
        import tree_sitter

        query = self._queries.get(query_type)
        if not query:
            return set()

        cursor = tree_sitter.QueryCursor(query)
        captures = cursor.captures(root_node)

        # Extract all capture tag names
        tags = set()
        for tag, nodes in captures.items():
            if nodes:  # Only add if there are actual matches
                tags.add(tag)
        return tags

class JSModuleResolver:
    """
    Resolves JavaScript module references across files.

    Tracks:
    - window.X = X patterns (global exports)
    - const X = require('./file') (CommonJS)
    - import X from './file' (ES6)
    - IIFE module patterns

    Usage:
        resolver = JSModuleResolver()
        resolver.analyze_file(file_path, content, parser)
        target = resolver.resolve_member_call('COLOR', 'subscribe', caller_file)
    """

    def __init__(self):
        # Map: global_name -> file_path (e.g., 'COLOR' -> 'color-engine.js')
        self.window_exports: Dict[str, str] = {}
        # Map: (file_path, local_name) -> source_module (e.g., ('app.js', 'COLOR') -> 'color-engine.js')
        self.import_aliases: Dict[Tuple[str, str], str] = {}
        # Map: file_path -> module_name (e.g., 'color-engine.js' -> 'COLOR')
        self.file_to_module: Dict[str, str] = {}
        # Parser for JS
        self.parser = None
        if TREE_SITTER_AVAILABLE and tree_sitter_javascript:
            assert tree_sitter is not None  # Guaranteed by TREE_SITTER_AVAILABLE
            try:
                lang = tree_sitter.Language(tree_sitter_javascript.language())
                self.parser = tree_sitter.Parser()
                self.parser.language = lang
            except Exception:
                pass

    def analyze_file(self, file_path: str, content: str) -> None:
        """Analyze a JS file to extract module aliases and exports."""
        if not self.parser or not content:
            return

        source_bytes = content.encode('utf-8')
        try:
            tree = self.parser.parse(source_bytes)
        except Exception:
            return

        file_name = Path(file_path).stem  # e.g., 'color-engine'

        def visit(node):
            # Pattern 1: window.X = X or window.X = {...}
            if node.type == 'assignment_expression':
                left = node.child_by_field_name('left')
                if left and left.type == 'member_expression':
                    obj = left.child_by_field_name('object')
                    prop = left.child_by_field_name('property')
                    if obj and prop and obj.text == b'window':
                        export_name = prop.text.decode()
                        self.window_exports[export_name] = file_path
                        self.file_to_module[file_path] = export_name

            # Pattern 2: const X = require('./file')
            if node.type == 'variable_declarator':
                name_node = node.child_by_field_name('name')
                value_node = node.child_by_field_name('value')
                if name_node and value_node and value_node.type == 'call_expression':
                    func = value_node.child_by_field_name('function')
                    if func and func.text == b'require':
                        args = value_node.child_by_field_name('arguments')
                        if args and args.child_count > 0:
                            arg = args.children[0] if args.children else None
                            if arg and arg.type == 'string':
                                module_path = arg.text.decode().strip('\'"')
                                local_name = name_node.text.decode()
                                self.import_aliases[(file_path, local_name)] = module_path

            # Pattern 3: import X from './file' or import { X } from './file'
            if node.type == 'import_statement':
                source_node = None
                for child in node.children:
                    if child.type == 'string':
                        source_node = child
                        break
                if source_node:
                    module_path = source_node.text.decode().strip('\'"')
                    # Find the imported names
                    for child in node.children:
                        if child.type == 'identifier':
                            local_name = child.text.decode()
                            self.import_aliases[(file_path, local_name)] = module_path
                        elif child.type == 'import_clause':
                            for subchild in child.children:
                                if subchild.type == 'identifier':
                                    local_name = subchild.text.decode()
                                    self.import_aliases[(file_path, local_name)] = module_path
                                elif subchild.type == 'named_imports':
                                    for spec in subchild.children:
                                        if spec.type == 'import_specifier':
                                            name = spec.child_by_field_name('name')
                                            if name:
                                                local_name = name.text.decode()
                                                self.import_aliases[(file_path, local_name)] = module_path

            # Pattern 4: const X = (function() {...})() - IIFE globals (browser script pattern)
            # These become globals in browser scripts loaded via <script> tags
            if node.type == 'lexical_declaration':
                for declarator in node.children:
                    if declarator.type == 'variable_declarator':
                        name_node = declarator.child_by_field_name('name')
                        value_node = declarator.child_by_field_name('value')
                        if name_node and name_node.type == 'identifier':
                            export_name = name_node.text.decode()
                            # Check if it's an IIFE: (function() {...})() or (() => {...})()
                            if value_node and value_node.type == 'call_expression':
                                func = value_node.child_by_field_name('function')
                                if func and func.type == 'parenthesized_expression':
                                    # It's an IIFE - register as a global
                                    if export_name not in self.window_exports:
                                        self.window_exports[export_name] = file_path
                                        self.file_to_module[file_path] = export_name

            for child in node.children:
                visit(child)

        visit(tree.root_node)

    def resolve_member_call(
        self,
        object_name: str,
        method_name: str,
        caller_file: str,
        particle_by_name: Dict[str, List[Dict]]
    ) -> Optional[Dict]:
        """
        Resolve a member call like COLOR.subscribe() to its target particle.

        Args:
            object_name: The object being called on (e.g., 'COLOR')
            method_name: The method being called (e.g., 'subscribe')
            caller_file: The file containing the call
            particle_by_name: Dict mapping names to particles

        Returns:
            The target particle, or None if not resolved
        """
        # Skip built-in objects
        if object_name in ('document', 'window', 'console', 'Math', 'JSON', 'Object', 'Array', 'String', 'Number'):
            return None

        # Strategy 1: Check window exports
        if object_name in self.window_exports:
            target_file = self.window_exports[object_name]
            # Look for method in that file
            candidates = particle_by_name.get(method_name, [])
            for c in candidates:
                if c.get('file_path') == target_file:
                    return c

        # Strategy 2: Check import aliases for this file
        alias_key = (caller_file, object_name)
        if alias_key in self.import_aliases:
            module_path = self.import_aliases[alias_key]
            # Resolve relative path
            if module_path.startswith('.'):
                caller_dir = str(Path(caller_file).parent)
                resolved = str(Path(caller_dir) / module_path)
                # Try with .js extension
                for ext in ['', '.js', '/index.js']:
                    test_path = resolved + ext
                    candidates = particle_by_name.get(method_name, [])
                    for c in candidates:
                        if test_path in c.get('file_path', ''):
                            return c

        # Strategy 3: Fuzzy match - object name might match file name
        # e.g., COLOR might come from color-engine.js or color.js
        # NOTE: Require match at START of filename to avoid false positives like
        # 'dm' matching 'legen-dm-anager' (substring match in wrong place)
        object_lower = object_name.lower()
        candidates = particle_by_name.get(method_name, [])
        for c in candidates:
            file_stem = Path(c.get('file_path', '')).stem.lower().replace('-', '').replace('_', '')
            # Match if object name starts the filename OR filename starts the object name
            # e.g., 'color' matches 'colorengine', 'data' matches 'datamanager'
            if file_stem.startswith(object_lower) or object_lower.startswith(file_stem):
                return c

        return None

    def get_stats(self) -> Dict[str, int]:
        """Return statistics about resolved modules."""
        return {
            'window_exports': len(self.window_exports),
            'import_aliases': len(self.import_aliases),
            'file_to_module': len(self.file_to_module),
        }

def get_js_module_resolver() -> JSModuleResolver:
    """Get or create the global JS module resolver."""
    global _js_module_resolver
    if _js_module_resolver is None:
        _js_module_resolver = JSModuleResolver()
    return _js_module_resolver

def _normalize_file_path(file_path: str) -> str:
    """Normalize file path to a resolved absolute string."""
    if not file_path:
        return ""
    try:
        return str(Path(file_path).resolve())
    except Exception:
        return file_path

def module_name_from_path(file_path: str) -> str:
    """Derive a module name from a file path."""
    path = Path(file_path)
    if path.stem == "__init__":
        return path.parent.name or path.stem
    return path.stem

def file_node_name(file_path: str, existing_ids: Optional[Set[str]] = None) -> str:
    """Compute a unique file-node name derived from the file path."""
    normalized = _normalize_file_path(file_path)
    base = module_name_from_path(normalized)
    if not existing_ids:
        return base

    candidate = _make_node_id(normalized, base)
    if candidate not in existing_ids:
        return base

    candidate_name = f"{base}.{FILE_NODE_SUFFIX}"
    candidate_id = _make_node_id(normalized, candidate_name)
    if candidate_id not in existing_ids:
        return candidate_name

    index = 2
    while True:
        candidate_name = f"{base}.{FILE_NODE_SUFFIX}{index}"
        candidate_id = _make_node_id(normalized, candidate_name)
        if candidate_id not in existing_ids:
            return candidate_name
        index += 1

def file_node_id(file_path: str, existing_ids: Optional[Set[str]] = None) -> str:
    """Build a canonical file-node id for a file path."""
    normalized = _normalize_file_path(file_path)
    name = file_node_name(normalized, existing_ids)
    return _make_node_id(normalized, name)

def _make_node_id(file_path: str, name: str) -> str:
    """Create a node ID in the canonical format: {full_path}:{name}"""
    return f"{file_path}:{name}"

def _get_particle_id(particle: Dict) -> str:
    """Get the canonical ID for a particle."""
    file_path = particle.get('file_path', '')
    name = particle.get('name', '')
    # Check if particle already has a full ID
    if particle.get('id'):
        return particle['id']
    return _make_node_id(file_path, name)

def _collect_file_node_ids(particles: List[Dict]) -> Dict[str, str]:
    """Collect file-node ids keyed by normalized file path."""
    mapping: Dict[str, str] = {}
    for particle in particles:
        metadata = particle.get("metadata") or {}
        if not metadata.get("file_node"):
            continue
        file_path = particle.get("file_path", "")
        if not file_path:
            continue
        mapping[_normalize_file_path(file_path)] = _get_particle_id(particle)
    return mapping

class DefaultEdgeStrategy(EdgeExtractionStrategy):
    """Fallback strategy for unknown languages (no body analysis)."""

    def extract_edges(self, particle: Dict, particle_by_name: Dict[str, List[Dict]]) -> List[Dict]:
        return []

class TreeSitterEdgeStrategy(EdgeExtractionStrategy):
    """
    Base class for Tree-sitter based edge extraction.
    Parses body_source as AST and runs queries for precise call detection.

    Enhanced with scope analysis:
    - Uses QueryBasedScopeAnalyzer to build scope graph
    - Filters out calls to local definitions (parameters, local variables)
    - Higher confidence for calls that resolve to known particles
    """

    def __init__(self, parser: Any, language_name: str):
        self.parser = parser
        self.language_name = language_name
        # Initialize scope analyzer if available
        self.scope_analyzer: Optional[Any] = None
        if SCOPE_ANALYZER_AVAILABLE and QueryBasedScopeAnalyzer is not None:
            self.scope_analyzer = QueryBasedScopeAnalyzer()

    def get_call_node_types(self) -> Set[str]:
        """Return set of AST node types that represent function calls."""
        return {'call', 'call_expression'}

    def extract_callee_name(self, node: Any, source_bytes: bytes) -> Optional[str]:
        """Extract the function/method name from a call node."""
        # Try 'function' field first (Python, JS)
        func_node = node.child_by_field_name('function')
        if func_node:
            # Direct identifier: func()
            if func_node.type == 'identifier':
                return func_node.text.decode()
            # Attribute access: obj.method() or self.method()
            if func_node.type in ('attribute', 'member_expression'):
                # Get the rightmost identifier (the method name)
                attr = func_node.child_by_field_name('attribute') or func_node.child_by_field_name('property')
                if attr:
                    return attr.text.decode()
        return None

    def extract_callee_with_location(self, node: Any, source_bytes: bytes) -> Optional[Tuple[str, int]]:
        """Extract callee name and its byte position for scope resolution."""
        func_node = node.child_by_field_name('function')
        if func_node:
            if func_node.type == 'identifier':
                return (func_node.text.decode(), func_node.start_byte)
            if func_node.type in ('attribute', 'member_expression'):
                attr = func_node.child_by_field_name('attribute') or func_node.child_by_field_name('property')
                if attr:
                    return (attr.text.decode(), attr.start_byte)
        return None

    def get_local_definitions(self, tree: Any, source: str) -> Set[str]:
        """
        Get names that are defined locally within this scope.
        These should not create edges to global particles.
        """
        if not self.scope_analyzer:
            return set()

        try:
            scope_graph = self.scope_analyzer.analyze(tree, source, self.language_name)
            local_names = set()
            for defn in scope_graph.definitions.values():
                # Only include non-global definitions
                if defn.scope_id != 0:  # scope_id 0 is typically the root/global scope
                    local_names.add(defn.name)
            return local_names
        except Exception:
            return set()

    def extract_edges(self, particle: Dict, particle_by_name: Dict[str, List[Dict]]) -> List[Dict]:
        edges = []
        body = particle.get('body_source', '')
        if not body or not self.parser:
            return edges

        caller_id = _get_particle_id(particle)
        caller_file = particle.get('file_path', '')
        source_bytes = body.encode('utf-8')

        try:
            tree = self.parser.parse(source_bytes)
        except Exception:
            return edges  # Fallback to empty if parsing fails

        # Get local definitions to filter out local calls
        local_defs = self.get_local_definitions(tree, body)

        call_types = self.get_call_node_types()
        found_calls: Set[str] = set()

        def visit(node):
            if node.type in call_types:
                callee = self.extract_callee_name(node, source_bytes)
                if callee:
                    found_calls.add(callee)
            for child in node.children:
                visit(child)

        visit(tree.root_node)

        # Match against known particles (prefer same-file)
        for call in found_calls:
            # Skip if the call refers to a local definition (parameter, local var)
            if call in local_defs:
                continue

            target = _find_target_particle(call, caller_file, particle_by_name)
            if target:
                target_id = _get_particle_id(target)
                edges.append({
                    'source': caller_id,
                    'target': target_id,
                    'edge_type': 'calls',
                    'family': 'Dependency',
                    'file_path': caller_file,
                    'line': particle.get('line', 0),
                    'confidence': 0.95,  # High confidence from AST
                })

        return edges

class PythonTreeSitterStrategy(TreeSitterEdgeStrategy):
    """Tree-sitter based Python call extraction."""

    def __init__(self):
        parser = None
        if TREE_SITTER_AVAILABLE and tree_sitter_python:
            assert tree_sitter is not None  # Guaranteed by TREE_SITTER_AVAILABLE
            try:
                lang = tree_sitter.Language(tree_sitter_python.language())
                parser = tree_sitter.Parser()
                parser.language = lang
            except Exception:
                parser = None
        super().__init__(parser, 'python')

    def get_call_node_types(self) -> Set[str]:
        return {'call'}

class JavaScriptTreeSitterStrategy(TreeSitterEdgeStrategy):
    """
    Tree-sitter based JavaScript/JSX call extraction with module resolution.

    Enhanced to handle:
    - Direct calls: func()
    - Member calls: COLOR.subscribe() -> resolved via JSModuleResolver
    - Constructor calls: new ClassName()
    - Callbacks: addEventListener('click', handler)
    - Method chaining: obj.method1().method2()
    """

    def __init__(self):
        parser = None
        if TREE_SITTER_AVAILABLE and tree_sitter_javascript:
            assert tree_sitter is not None  # Guaranteed by TREE_SITTER_AVAILABLE
            try:
                lang = tree_sitter.Language(tree_sitter_javascript.language())
                parser = tree_sitter.Parser()
                parser.language = lang
            except Exception:
                parser = None
        super().__init__(parser, 'javascript')

    def get_call_node_types(self) -> Set[str]:
        return {'call_expression', 'new_expression'}

    def extract_member_call(self, node: Any, source_bytes: bytes) -> Tuple[Optional[str], Optional[str]]:
        """
        Extract both object and method from a member call.

        Returns:
            (object_name, method_name) tuple, e.g., ('COLOR', 'subscribe')
            (None, method_name) for direct calls like func()
        """
        func_node = node.child_by_field_name('function')
        if not func_node:
            return (None, None)

        # Direct call: func()
        if func_node.type == 'identifier':
            return (None, func_node.text.decode())

        # Member call: obj.method() or this.method()
        if func_node.type == 'member_expression':
            obj_node = func_node.child_by_field_name('object')
            prop_node = func_node.child_by_field_name('property')
            if obj_node and prop_node:
                # Handle 'this' keyword - return 'this' as obj_name for semantic tracking
                # (resolution will use same-file preference which is correct for this)
                if obj_node.type == 'this':
                    obj_name = 'this'
                elif obj_node.type == 'identifier':
                    obj_name = obj_node.text.decode()
                else:
                    obj_name = None
                method_name = prop_node.text.decode() if prop_node.type == 'property_identifier' else None
                return (obj_name, method_name)

        return (None, None)

    def extract_callback_args(self, node: Any, source_bytes: bytes) -> List[str]:
        """
        Extract callback function references from call arguments.

        Handles patterns like:
        - addEventListener('click', handleClick)
        - array.map(processItem)
        - promise.then(onSuccess, onError)
        """
        callbacks = []
        args_node = node.child_by_field_name('arguments')
        if not args_node:
            return callbacks

        for arg in args_node.children:
            # Direct function reference: addEventListener('click', handler)
            if arg.type == 'identifier':
                callbacks.append(arg.text.decode())
            # Could also handle arrow functions with named calls inside, but that's complex

        return callbacks

    def extract_callee_name(self, node: Any, source_bytes: bytes) -> Optional[str]:
        """Extract just the method name (for backward compatibility)."""
        if node.type == 'new_expression':
            constructor = node.child_by_field_name('constructor')
            if constructor and constructor.type == 'identifier':
                return constructor.text.decode()
        _, method = self.extract_member_call(node, source_bytes)
        return method

    def extract_edges(self, particle: Dict, particle_by_name: Dict[str, List[Dict]]) -> List[Dict]:
        """
        Extract edges with full module resolution for JS.

        Enhanced to:
        1. Resolve member calls via JSModuleResolver
        2. Track callback references
        3. Fall back to same-file preference for unresolved calls
        """
        edges = []
        body = particle.get('body_source', '')
        if not body or not self.parser:
            return edges

        caller_id = _get_particle_id(particle)
        caller_file = particle.get('file_path', '')
        source_bytes = body.encode('utf-8')

        try:
            tree = self.parser.parse(source_bytes)
        except Exception:
            return edges

        resolver = get_js_module_resolver()
        call_types = self.get_call_node_types()
        # Key by (obj_name, method_name) to avoid dropping edges when different objects
        # call the same method name (e.g., ANIM.init() vs GRAPH.init())
        processed: Set[Tuple[Optional[str], str]] = set()

        def visit(node):
            if node.type in call_types:
                # Extract full member call info
                obj_name, method_name = self.extract_member_call(node, source_bytes)

                if method_name:
                    edge_key = (obj_name, method_name)
                    if edge_key not in processed:
                        processed.add(edge_key)
                        target = None

                        # Strategy 1: If it's 'this.method()', use same-file preference directly
                        # (this refers to methods in the same class/object)
                        if obj_name == 'this':
                            target = _find_target_particle(method_name, caller_file, particle_by_name)

                        # Strategy 2: If it's a member call (obj.method), use resolver
                        elif obj_name:
                            target = resolver.resolve_member_call(
                                obj_name, method_name, caller_file, particle_by_name
                            )

                        # Strategy 3: Fall back to same-file preference for direct calls
                        if not target:
                            target = _find_target_particle(method_name, caller_file, particle_by_name)

                        if target:
                            target_id = _get_particle_id(target)
                            edges.append({
                                'source': caller_id,
                                'target': target_id,
                                'edge_type': 'calls',
                                'family': 'Dependency',
                                'file_path': caller_file,
                                'line': particle.get('line', 0),
                                'confidence': 0.95 if obj_name and obj_name != 'this' else 0.85,
                            })

                # Also extract callbacks from arguments
                callbacks = self.extract_callback_args(node, source_bytes)
                for cb_name in callbacks:
                    cb_key = (None, cb_name)  # Callbacks are direct references (no object)
                    if cb_key not in processed:
                        processed.add(cb_key)
                        target = _find_target_particle(cb_name, caller_file, particle_by_name)
                        if target:
                            target_id = _get_particle_id(target)
                            edges.append({
                                'source': caller_id,
                                'target': target_id,
                                'edge_type': 'calls',
                                'family': 'Dependency',
                                'file_path': caller_file,
                                'line': particle.get('line', 0),
                                'confidence': 0.80,  # Callback reference
                            })

            for child in node.children:
                visit(child)

        visit(tree.root_node)
        return edges

class TypeScriptTreeSitterStrategy(TreeSitterEdgeStrategy):
    """Tree-sitter based TypeScript/TSX call extraction."""

    def __init__(self):
        parser = None
        if TREE_SITTER_AVAILABLE and tree_sitter_typescript:
            assert tree_sitter is not None  # Guaranteed by TREE_SITTER_AVAILABLE
            try:
                lang = tree_sitter.Language(tree_sitter_typescript.language_typescript())
                parser = tree_sitter.Parser()
                parser.language = lang
            except Exception:
                parser = None
        super().__init__(parser, 'typescript')

    def get_call_node_types(self) -> Set[str]:
        return {'call_expression', 'new_expression'}

    def extract_callee_name(self, node: Any, source_bytes: bytes) -> Optional[str]:
        if node.type == 'new_expression':
            constructor = node.child_by_field_name('constructor')
            if constructor and constructor.type == 'identifier':
                return constructor.text.decode()
        return super().extract_callee_name(node, source_bytes)

def get_strategy_for_file(file_path: str) -> EdgeExtractionStrategy:
    """
    Factory to get the correct strategy based on file extension.
    Prefers Tree-sitter strategies when available, falls back to regex.
    """
    if file_path.endswith('.py'):
        # Try Tree-sitter first
        if TREE_SITTER_AVAILABLE and tree_sitter_python:
            strategy = PythonTreeSitterStrategy()
            if strategy.parser:
                return strategy
        return PythonEdgeStrategy()  # Regex fallback

    if file_path.endswith('.js') or file_path.endswith('.jsx'):
        if TREE_SITTER_AVAILABLE and tree_sitter_javascript:
            strategy = JavaScriptTreeSitterStrategy()
            if strategy.parser:
                return strategy
        return JavascriptEdgeStrategy()  # Regex fallback

    if file_path.endswith('.ts') or file_path.endswith('.tsx'):
        if TREE_SITTER_AVAILABLE and tree_sitter_typescript:
            strategy = TypeScriptTreeSitterStrategy()
            if strategy.parser:
                return strategy
        return TypeScriptEdgeStrategy()  # Regex fallback

    if file_path.endswith('.go'):
        return GoEdgeStrategy()
    if file_path.endswith('.rs'):
        return RustEdgeStrategy()
    return DefaultEdgeStrategy()

def _extract_exposure_edges_from_body(body: str, file_path: str, particle_by_name: Dict[str, List[Dict]]) -> List[Tuple[str, str]]:
    """
    Extract module.exports, export statements from source code.

    Returns list of (exported_symbol_name, export_type) tuples.
    Export types: 'named', 'default', 'commonjs'
    """
    exposures = []

    if not body:
        return exposures

    # CommonJS patterns
    # Pattern 1: module.exports = X (not module.exports.X)
    module_exports = re.findall(r'module\.exports\s*=\s*(\w+)(?!\.)', body)
    for sym in module_exports:
        if sym and sym not in ('null', 'undefined'):
            exposures.append((sym, 'commonjs'))

    # Pattern 2: module.exports.X = Y
    module_exports_named = re.findall(r'module\.exports\.(\w+)\s*=', body)
    for sym in module_exports_named:
        if sym:
            exposures.append((sym, 'commonjs'))

    # Pattern 3: exports.X = Y (shorthand for module.exports.X, but NOT module.exports)
    # Use negative lookbehind to exclude "module.exports"
    exports_named = re.findall(r'(?<!module\.)exports\.(\w+)\s*=', body)
    for sym in exports_named:
        if sym:
            exposures.append((sym, 'commonjs'))

    # ES6 patterns
    # Pattern 4: export function X or export const X or export let X or export var X
    export_func_const = re.findall(r'export\s+(?:function|const|let|var)\s+(\w+)', body)
    for sym in export_func_const:
        if sym:
            exposures.append((sym, 'named'))

    # Pattern 5: export class X
    export_class = re.findall(r'export\s+class\s+(\w+)', body)
    for sym in export_class:
        if sym:
            exposures.append((sym, 'named'))

    # Pattern 6: export default X
    export_default = re.findall(r'export\s+default\s+(\w+|\{[^}]+\})', body)
    for sym in export_default:
        if sym and sym not in ('function', 'class'):
            # Clean up object literals
            sym = sym.strip('{}').split(',')[0].strip() if '{' in sym else sym
            if sym:
                exposures.append((sym, 'default'))

    # Pattern 7: export { X, Y, Z } - named exports
    export_named_list = re.findall(r'export\s+\{\s*([^}]+)\s*\}', body)
    for exports_str in export_named_list:
        # Split by comma and extract names
        names = re.findall(r'(\w+)(?:\s+as\s+\w+)?', exports_str)
        for name in names:
            if name:
                exposures.append((name, 'named'))

    # Python patterns
    # Pattern 8: __all__ = ['X', 'Y', 'Z']
    all_exports = re.findall(r'__all__\s*=\s*\[([^\]]+)\]', body)
    for exports_str in all_exports:
        # Extract quoted strings
        names = re.findall(r'[\'"](\w+)[\'"]', exports_str)
        for name in names:
            if name:
                exposures.append((name, 'python_all'))

    return exposures

def deduplicate_edges(edges: List[Dict]) -> List[Dict]:
    """Remove duplicate edges based on source, target, and type."""
    seen = set()
    unique = []
    for edge in edges:
        key = (edge.get("source"), edge.get("target"), edge.get("type"))
        if key not in seen:
            seen.add(key)
            unique.append(edge)
    return unique

def _is_canonical_id(target: str) -> bool:
    """Check if target looks like a canonical ID (path:name format)."""
    return ':' in target and ('/' in target or '\\' in target)

def _extract_node_path(node_id: str) -> Optional[str]:
    """Extract the file path portion from a canonical node id."""
    if not node_id:
        return None
    if "::" in node_id:
        path_part = node_id.split("::", 1)[0]
    elif ":" in node_id:
        path_part = node_id.rsplit(":", 1)[0]
    else:
        return None
    try:
        return str(Path(path_part).resolve())
    except Exception:
        return path_part

def _build_file_to_node_ids(node_ids: Set[str]) -> Dict[str, List[str]]:
    """Build a mapping from absolute file path to node ids for that file."""
    mapping: Dict[str, List[str]] = {}
    for node_id in node_ids:
        path = _extract_node_path(node_id)
        if not path:
            continue
        mapping.setdefault(path, []).append(node_id)
    for key in mapping:
        mapping[key].sort()
    return mapping

