class ExecutionFlow:
    """Complete execution flow analysis of a codebase"""
    nodes: Dict[str, FlowNode]
    chains: List[CausalityChain]
    orphans: List[str]
    entry_points: List[str]
    integration_errors: List[IntegrationError]

    # Statistics
    total_nodes: int = 0
    reachable_nodes: int = 0
    dead_code_percent: float = 0.0

    # Reachability data (orphan_id -> path from nearest entry)
    reachability_paths: Dict[str, List[str]] = field(default_factory=dict)

    def summary(self) -> dict:
        """Summarize execution flow"""
        layer_distribution = defaultdict(int)
        orphan_by_layer = defaultdict(list)

        for node in self.nodes.values():
            layer_distribution[node.layer] += 1
            if node.is_orphan:
                orphan_by_layer[node.layer].append(node.name)

        return {
            "total_nodes": self.total_nodes,
            "entry_points": len(self.entry_points),
            "reachable_nodes": self.reachable_nodes,
            "orphan_count": len(self.orphans),
            "dead_code_percent": self.dead_code_percent,
            "chains_count": len(self.chains),
            "integration_errors": len(self.integration_errors),
            "layer_distribution": dict(layer_distribution),
            "orphans_by_layer": {k: len(v) for k, v in orphan_by_layer.items()}
        }

    def correlate_with_purpose(self, purpose_field) -> dict:
        """Correlate execution flow with purpose field"""
        # Count flow violations by layer pair
        layer_violations = defaultdict(int)

        for chain in self.chains:
            if chain.has_violation:
                for i in range(len(chain.layers_crossed) - 1):
                    pair = f"{chain.layers_crossed[i]} → {chain.layers_crossed[i+1]}"
                    layer_violations[pair] += 1

        return {
            "flow_layer_violations": dict(layer_violations),
            "orphans_with_purpose": {
                node_id: self.nodes[node_id].role 
                for node_id in self.orphans 
                if node_id in self.nodes
            }
        }

def detect_class_instantiation(nodes: List[Dict], edges: List[Dict]) -> int:
    """
    detect_class_instantiation (Task #7):
    Find edges from code instantiating a class to the class definition.
    Pattern: x = MyClass() -> invokes edge
    """
    new_edges = 0

    classes_by_name = defaultdict(list)
    for n in nodes:
        # UPDATED: Check 'kind' OR 'type' for robustness
        if n.get('kind') == 'class' or n.get('type') == 'class':
            classes_by_name[n.get('name', '')].append(n.get('id'))

    # 2. Scan all nodes for usage
    for src_node in nodes:
        body = src_node.get('body_source', '')
        if not body:
            continue

        # Naive pattern: look for ClassName()
        # (This is a heuristic, better would be AST analysis, but sticking to regex for 'light' Collider)
        import re
        for class_name, targets in classes_by_name.items():
            # Skip common/short names to avoid noise
            if len(class_name) < 4:
                continue

            # Regex: Word boundary + ClassName + (
            if re.search(r'\b' + re.escape(class_name) + r'\s*\(', body):
                for target_id in targets:
                    if target_id == src_node.get('id'):
                        continue

                    edges.append({
                        'source': src_node.get('id'),
                        'target': target_id,
                        'edge_type': 'instantiates',
                        'family': 'Dependency',
                        'inferred': True,
                        'confidence': 0.6,
                        'description': f"Class instantiation {class_name}() detected"
                    })
                    new_edges += 1

    return new_edges

