def _get_schema():
    """Lazy-load unified atom schema if available."""
    global _SCHEMA
    if _SCHEMA is not None:
        return _SCHEMA
    try:
        from src.core.unified_atom_schema import get_unified_schema
    except ImportError:
        try:
